-affairs","exam_relevance":["WBCS","WBPSC_CLERKSHIP","WBPSC_MISC","WBP_CONSTABLE","WBP_SI","KOLKATA_POLICE","SSC","RAILWAY","BANKING"],"chapters":[{"key":"current-affairs:national","name":"জাতীয় সাম্প্রতিক ঘটনা","display_order":1,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:national:t01","name":"কেন্দ্রীয় নীতি ও সিদ্ধান্ত"},{"key":"current-affairs:national:t02","name":"জাতীয় প্রতিষ্ঠান ও প্রশাসন"},{"key":"current-affairs:national:t03","name":"গুরুত্বপূর্ণ আইন ও বিচারিক ঘটনা"},{"key":"current-affairs:national:t04","name":"জাতীয় সামাজিক ও অর্থনৈতিক উন্নয়ন"}]},{"key":"current-affairs:international","name":"আন্তর্জাতিক সাম্প্রতিক ঘটনা","display_order":2,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:international:t01","name":"দ্বিপাক্ষিক ও বহুপাক্ষিক সম্পর্ক"},{"key":"current-affairs:international:t02","name":"আন্তর্জাতিক সংঘাত ও কূটনীতি"},{"key":"current-affairs:international:t03","name":"জাতিসংঘ ও আন্তর্জাতিক সংস্থা"},{"key":"current-affairs:international:t04","name":"বিশ্ব অর্থনীতি ও মানবিক ঘটনা"}]},{"key":"current-affairs:west-bengal","name":"পশ্চিমবঙ্গের সাম্প্রতিক ঘটনা","display_order":3,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:west-bengal:t01","name":"রাজ্য সরকার ও প্রশাসন"},{"key":"current-affairs:west-bengal:t02","name":"পশ্চিমবঙ্গের অর্থনীতি ও পরিকাঠামো"},{"key":"current-affairs:west-bengal:t03","name":"রাজ্যের শিক্ষা, স্বাস্থ্য ও সমাজ"},{"key":"current-affairs:west-bengal:t04","name":"রাজ্যের সংস্কৃতি, পরিবেশ ও ক্রীড়া"}]},{"key":"current-affairs:awards-appointments","name":"পুরস্কার ও নিয়োগ","display_order":4,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:awards-appointments:t01","name":"জাতীয় ও আন্তর্জাতিক নিয়োগ"},{"key":"current-affairs:awards-appointments:t02","name":"ভারতীয় পুরস্কার ও সম্মান"},{"key":"current-affairs:awards-appointments:t03","name":"আন্তর্জাতিক পুরস্কার"},{"key":"current-affairs:awards-appointments:t04","name":"গুরুত্বপূর্ণ পদত্যাগ ও নির্বাচন"}]},{"key":"current-affairs:sports","name":"খেলাধুলা","display_order":5,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:sports:t01","name":"জাতীয় ও আন্তর্জাতিক প্রতিযোগিতা"},{"key":"current-affairs:sports:t02","name":"বিজয়ী, রেকর্ড ও র‍্যাঙ্কিং"},{"key":"current-affairs:sports:t03","name":"ভারতীয় ক্রীড়াবিদ"},{"key":"current-affairs:sports:t04","name":"ক্রীড়া সংস্থা, আয়োজক ও মাসকট"}]},{"key":"current-affairs:science-technology","name":"বিজ্ঞান ও প্রযুক্তি","display_order":6,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:science-technology:t01","name":"মহাকাশ ও প্রতিরক্ষা প্রযুক্তি"},{"key":"current-affairs:science-technology:t02","name":"স্বাস্থ্য ও জৈবপ্রযুক্তি"},{"key":"current-affairs:science-technology:t03","name":"ডিজিটাল, AI ও যোগাযোগ প্রযুক্তি"},{"key":"current-affairs:science-technology:t04","name":"গবেষণা, উদ্ভাবন ও বিজ্ঞান পুরস্কার"}]},{"key":"current-affairs:government-schemes","name":"সরকারি প্রকল্প","display_order":7,"priority":3,"rotation_enabled":true,"micro_topics":[{"key":"current-affairs:government-schemes:t01","name":"কেন্দ্রীয় কল্যাণ প্রকল্প"},{"key":"current-affairs:government-schemes:t02","name":"পশ্চিমবঙ্গের প্রকল্প"},{"key":"current-affairs:government-schemes:t03","name":"কৃষি, কর্মসংস্থান ও আর্থিক অন্তর্ভুক্তি"},{"key":"current-affairs:government-schemes:t04","name":"স্বাস্থ্য, শিক্ষা, নারী ও শিশু প্রকল্প"}]},{"key":"current-affairs:economy-reports","name":"অর্থনীতি, প্রতিবেদন ও সূচক","display_order":8,"priority":3,"rotation_enabled":false,"micro_topics":[{"key":"current-affairs:economy-reports:t01","name":"বাজেট, নীতি ও অর্থনৈতিক সিদ্ধান্ত"},{"key":"current-affairs:economy-reports:t02","name":"RBI, ব্যাংকিং ও আর্থিক বাজার"},{"key":"current-affairs:economy-reports:t03","name":"জাতীয় ও আন্তর্জাতিক প্রতিবেদন"},{"key":"current-affairs:economy-reports:t04","name":"সূচক, র‍্যাঙ্কিং ও জরিপ"}]},{"key":"current-affairs:defence-summits","name":"প্রতিরক্ষা, মহড়া ও সম্মেলন","display_order":9,"priority":3,"rotation_enabled":false,"micro_topics":[{"key":"current-affairs:defence-summits:t01","name":"প্রতিরক্ষা ক্রয় ও অস্ত্র ব্যবস্থা"},{"key":"current-affairs:defence-summits:t02","name":"সামরিক মহড়া"},{"key":"current-affairs:defence-summits:t03","name":"আন্তর্জাতিক শীর্ষ সম্মেলন"},{"key":"current-affairs:defence-summits:t04","name":"ভারতের কূটনৈতিক সফর ও চুক্তি"}]},{"key":"current-affairs:environment-culture","name":"পরিবেশ, সংস্কৃতি ও অন্যান্য সাম্প্রতিক বিষয়","display_order":10,"priority":2,"rotation_enabled":false,"micro_topics":[{"key":"current-affairs:environment-culture:t01","name":"জলবায়ু ও জীববৈচিত্র্য ঘটনা"},{"key":"current-affairs:environment-culture:t02","name":"বই, লেখক ও গুরুত্বপূর্ণ মৃত্যু"},{"key":"current-affairs:environment-culture:t03","name":"উৎসব, ঐতিহ্য ও GI Tag"},{"key":"current-affairs:environment-culture:t04","name":"গুরুত্বপূর্ণ দিবস, থিম ও জনসচেতনতা"}]}]}]$catalogue$::jsonb)
    loop
        update public.quiz_subjects
        set exam_relevance = array(
                select jsonb_array_elements_text(subject_entry->'exam_relevance')
            ),
            updated_at = now()
        where subject_key = subject_entry->>'subject_key';

        if not found then
            raise exception 'Unknown canonical syllabus subject: %', subject_entry->>'subject_key';
        end if;

        for chapter_entry in
            select value from jsonb_array_elements(subject_entry->'chapters')
        loop
            insert into public.quiz_chapters (
                subject_key, key, name, normalized_name, display_order,
                exam_relevance, priority, rotation_enabled, syllabus_version, active
            ) values (
                subject_entry->>'subject_key',
                chapter_entry->>'key',
                chapter_entry->>'name',
                lower(btrim(chapter_entry->>'name')),
                (chapter_entry->>'display_order')::integer,
                array(select jsonb_array_elements_text(subject_entry->'exam_relevance')),
                (chapter_entry->>'priority')::smallint,
                (chapter_entry->>'rotation_enabled')::boolean,
                2,
                true
            )
            on conflict (subject_key, name) do update set
                key = excluded.key,
                normalized_name = excluded.normalized_name,
                display_order = excluded.display_order,
                exam_relevance = excluded.exam_relevance,
                priority = excluded.priority,
                rotation_enabled = excluded.rotation_enabled,
                syllabus_version = excluded.syllabus_version,
                active = true,
                updated_at = now()
            returning id into chapter_id;

            for topic_entry in
                select value from jsonb_array_elements(chapter_entry->'micro_topics')
            loop
                insert into public.quiz_micro_topics (
                    chapter_id, key, name, normalized_name, exam_relevance,
                    difficulty_targets, target_coverage, mastery_relevance,
                    priority, syllabus_version, active
                ) values (
                    chapter_id,
                    topic_entry->>'key',
                    topic_entry->>'name',
                    lower(btrim(topic_entry->>'name')),
                    array(select jsonb_array_elements_text(subject_entry->'exam_relevance')),
                    case (chapter_entry->>'priority')::smallint
                        when 3 then '{"easy":2,"medium":5,"hard":3}'::jsonb
                        when 2 then '{"easy":3,"medium":5,"hard":2}'::jsonb
                        else '{"easy":4,"medium":5,"hard":1}'::jsonb
                    end,
                    case (chapter_entry->>'priority')::smallint
                        when 3 then 20 when 2 then 12 else 8
                    end,
                    case (chapter_entry->>'priority')::smallint
                        when 3 then 2.0 when 2 then 1.5 else 1.0
                    end,
                    (chapter_entry->>'priority')::smallint,
                    2,
                    true
                )
                on conflict (key) do update set
                    chapter_id = excluded.chapter_id,
                    name = excluded.name,
                    normalized_name = excluded.normalized_name,
                    exam_relevance = excluded.exam_relevance,
                    difficulty_targets = excluded.difficulty_targets,
                    target_coverage = excluded.target_coverage,
                    mastery_relevance = excluded.mastery_relevance,
                    priority = excluded.priority,
                    syllabus_version = excluded.syllabus_version,
                    active = true,
                    updated_at = now();
            end loop;
        end loop;
    end loop;
end;
$seed$;

alter table public.quiz_subjects enable row level security;
alter table public.quiz_chapters enable row level security;
alter table public.quiz_micro_topics enable row level security;

revoke all on table public.quiz_subjects, public.quiz_chapters,
    public.quiz_micro_topics from public, anon, authenticated;
grant select, insert, update, delete on table public.quiz_subjects,
    public.quiz_chapters, public.quiz_micro_topics to service_role;
